#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N;
        scanf("%lld", &N);
        long long count = 0;
        for (long long i = 1; i <= N; i++) {
            long long j = i;
            int found = 0;
            while (j > 0) {
                if (j % 10 == i % 10) {
                    found = 1;
                    break;
                }
                j /= 10;
            }
            if (found) count++;
        }
        printf("%lld/%lld\n", count, N);
    }
    return 0;
}

