import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long N = sc.nextLong();
            long count = 0;
            for (long i = 1; i <= N; i++) {
                long j = i;
                int found = 0;
                while (j > 0) {
                    if (j % 10 == i % 10) {
                        found = 1;
                        break;
                    }
                    j /= 10;
                }
                if (found) count++;
            }
            System.out.println(count + "/" + N);
        }
    }
}

